SELECT * FROM /* 从日志表 */ user WHERE 1=1
/* 指定查询条件(对应字段必须包含相关字符串) */
AND ( userId LIKE CONCAT('%', #{match}, '%') OR username LIKE CONCAT('%', #{match}, '%') OR password LIKE CONCAT('%', #{match}, '%') OR userPermission LIKE CONCAT('%', #{match}, '%') )
/* 指定排序方式 */ ORDER BY
-- 假设按id降序排序，根据实际情况选择字段 userId DESC
-- 默认升序排序 userId ASC
/* 指定分页 */ LIMIT #{offset}, #{pageSize}
